class _Node:
    __slots__ = ("x", "y", "weight", "f", "g", "h", "visited", "closed", "parent")

    def __init__(self, x, y, weight):
        self.x = x
        self.y = y
        self.weight = weight
        self.f = 0
        self.g = 0
        self.h = 0
        self.visited = False
        self.closed = False
        self.parent = None


_width = len(_GRID_DATA)
_height = len(_GRID_DATA[0])

_grid = []
_dirty = []

for x in range(_width):
    col = []
    s = _GRID_DATA[x]
    for y in range(_height):
        col.append(_Node(x, y, ord(s[y]) - 48))
    _grid.append(col)


def _clean_dirty():
    for n in _dirty:
        n.f = 0
        n.g = 0
        n.h = 0
        n.visited = False
        n.closed = False
        n.parent = None
    _dirty.clear()


def _neighbors(x, y):
    result = []
    if x > 0:
        result.append(_grid[x - 1][y])
    if x < _width - 1:
        result.append(_grid[x + 1][y])
    if y > 0:
        result.append(_grid[x][y - 1])
    if y < _height - 1:
        result.append(_grid[x][y + 1])
    return result


_heap = []


def _heap_push(node):
    _heap.append(node)
    f = node.f
    i = len(_heap) - 1
    while i > 0:
        p = (i - 1) >> 1
        if f < _heap[p].f:
            _heap[i] = _heap[p]
            _heap[p] = node
            i = p
        else:
            break


def _heap_pop():
    result = _heap[0]
    last = _heap.pop()
    n = len(_heap)
    if n > 0:
        _heap[0] = last
        f = last.f
        i = 0
        while True:
            c1 = 2 * i + 1
            c2 = c1 + 1
            swap = -1
            swap_f = f
            if c1 < n and _heap[c1].f < f:
                swap = c1
                swap_f = _heap[c1].f
            if c2 < n and _heap[c2].f < swap_f:
                swap = c2
            if swap != -1:
                _heap[i] = _heap[swap]
                _heap[swap] = last
                i = swap
            else:
                break
    return result


def _heap_rescore(node):
    for idx in range(len(_heap)):
        if _heap[idx] is node:
            f = node.f
            while idx > 0:
                p = (idx - 1) >> 1
                if f < _heap[p].f:
                    _heap[idx] = _heap[p]
                    _heap[p] = node
                    idx = p
                else:
                    break
            return


def _search(start, end):
    _clean_dirty()
    _heap.clear()

    start.h = abs(start.x - end.x) + abs(start.y - end.y)
    _dirty.append(start)
    _heap_push(start)

    while len(_heap) > 0:
        current = _heap_pop()

        if current is end:
            path = []
            curr = current
            while curr.parent is not None:
                path.append(curr)
                curr = curr.parent
            path.reverse()
            return path

        current.closed = True

        for nb in _neighbors(current.x, current.y):
            if nb.closed or nb.weight == 0:
                continue

            g_score = current.g + nb.weight
            been_visited = nb.visited

            if not been_visited or g_score < nb.g:
                nb.visited = True
                nb.parent = current
                if nb.h == 0:
                    nb.h = abs(nb.x - end.x) + abs(nb.y - end.y)
                nb.g = g_score
                nb.f = g_score + nb.h
                _dirty.append(nb)

                if not been_visited:
                    _heap_push(nb)
                else:
                    _heap_rescore(nb)

    return []


result = _search(_grid[0][0], _grid[123][321])

if len(result) != _EXPECTED_LEN:
    raise SystemExit(f"bad path length: {len(result)} expected {_EXPECTED_LEN}")

for i, node in enumerate(result):
    if node.x != _EXPECTED_PATH[i * 2] or node.y != _EXPECTED_PATH[i * 2 + 1]:
        raise SystemExit(f"bad path at node {i}")

print("ok")
